def bell_number(n: int) -> int:
    if n < 0:
        raise ValueError("n must be a non-negative integer")
    if n == 0:
        return 1

    # Bell triangle (Aitken's array)
    # First row: [1]
    # Each subsequent row starts with the last element of the previous row
    # Each element after the first is the sum of the element to its left and the element above-left

    triangle = [[1]]

    for i in range(1, n + 1):
        prev_row = triangle[-1]
        new_row = [prev_row[-1]]  # Start with the last element of the previous row
        for j in range(len(prev_row)):
            if j < len(new_row):
                new_row.append(new_row[j] + prev_row[j])
            else:
                new_row.append(prev_row[j])
        triangle.append(new_row)

    return triangle[n][0]
