    """
    Check whether the given number is undulating.
    An undulating number is a positive integer whose digits alternate between two digits,
    e.g., 121212, 343434, 121, 12321 are NOT undulating in the strict sense of repeating two digits.
    Strict definition: number must start with a digit, then alternate between two different digits.
    Examples: 121212, 232323, 121, 232, 1212, etc.
    """
    s = str(n)
    if len(s) < 3:
        return False

    d1 = int(s[0])
    d2 = int(s[1])

    if d1 == d2:
        return False

    for i in range(2, len(s)):
        curr = int(s[i])
        if i % 2 == 0:
            if curr != d1:
                return False
        else:
            if curr != d2:
                return False

    return True
