def odd_Equivalent(binary_string: str, rotations: int) -> int:
    n = len(binary_string)
    if rotations == 0:
        rotations = n

    rotations %= n
    if rotations == 0:
        original = binary_string
    else:
        original = binary_string[-rotations:] + binary_string[:-rotations]

    count = 0
    for r in range(rotations, n + rotations):
        rotated = original[r - rotations:] + original[:r - rotations]
        if int(rotated, 2) % 2 == 1:
            count += 1

    return count
