        return None

    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is even or odd
        if mid % 2 == 1:
            mid -= 1

        # If pair is broken, the single element is at mid or to the left
        if arr[mid] != arr[mid + 1]:
            right = mid
        else:
            left = mid + 2

    return arr[left]
