            return False

    # Check column sums
    for col in range(n):
        if sum(matrix[row][col] for row in range(n)) != expected_sum:
            return False

    # Check diagonal sums
    if sum(matrix[i][i] for i in range(n)) != expected_sum:
        return False

    if sum(matrix[i][n - 1 - i] for i in range(n)) != expected_sum:
        return False

    # Check if all numbers from 1 to n^2 are present
    seen = set()
    for row in matrix:
        for num in row:
            if num < 1 or num > n * n or num in seen:
                return False
            seen.add(num)

    return True
