def magic_square_test(matrix):
    if not matrix or not matrix[0]:
        return False

    n = len(matrix)
    m = len(matrix[0])

    if n != m:
        return False

    if n == 1:
        return True

    if n == 2:
        return False

    # Check if all elements are distinct and in range 1 to n*n
    expected_sum = n * (n * n + 1) // 2
    seen = set()
    for row in matrix:
        for val in row:
            if val < 1 or val > n * n or val in seen:
                return False
            seen.add(val)

    # Calculate row sums
    row_sums = [sum(row) for row in matrix]
    if any(s != expected_sum for s in row_sums):
        return False

    # Calculate column sums
    col_sums = [sum(matrix[r][c] for r in range(n)) for c in range(n)]
    if any(s != expected_sum for s in col_sums):
        return False

    # Calculate diagonal sums
    diag1 = sum(matrix[i][i] for i in range(n))
    diag2 = sum(matrix[i][n - 1 - i] for i in range(n))

    return diag1 == expected_sum and diag2 == expected_sum
