def pancake_sort(arr):
    def flip(arr, k):
        arr[:k+1] = arr[:k+1][::-1]
        return arr

    n = len(arr)
    for curr in range(n, 1, -1):
        # Find index of the maximum element in arr[0..curr-1]
        max_idx = 0
        for i in range(1, curr):
            if arr[i] > arr[max_idx]:
                max_idx = i

        # If max element is not at the end
        if max_idx != curr - 1:
            # Move max element to the front
            flip(arr, max_idx)
            # Move max element to its correct position at the end
            flip(arr, curr - 1)

    return arr
