def is_majority(arr, n, element):
    if n == 0:
        return False

    # In a sorted array, if element is majority, it must occupy the middle index
    mid = n // 2
    if arr[mid] != element:
        return False

    # Count occurrences of element
    count = 0
    left, right = 0, n - 1

    # Binary search for first occurrence
    first = -1
    while left <= right:
        mid_idx = (left + right) // 2
        if arr[mid_idx] == element:
            first = mid_idx
            right = mid_idx - 1
        elif arr[mid_idx] < element:
            left = mid_idx + 1
        else:
            right = mid_idx - 1

    # Binary search for last occurrence
    last = -1
    left, right = 0, n - 1
    while left <= right:
        mid_idx = (left + right) // 2
        if arr[mid_idx] == element:
            last = mid_idx
            left = mid_idx + 1
        elif arr[mid_idx] < element:
            left = mid_idx + 1
        else:
            right = mid_idx - 1

    if first == -1 or last == -1:
        return False

    count = last - first + 1
    return count > n // 2
