def get_total_number_of_sequences(m: int, n: int) -> int:
    """
    Returns the number of sequences of length n where:
      - Each element is a positive integer.
      - For each i from 1 to n-1: a[i] >= 2 * a[i-1]
      - All elements are <= m.

    Uses dynamic programming: dp[i][v] = number of valid sequences of length i ending with value v.
    """
    if n == 0:
        return 0
    if m < 1:
        return 0

    # dp[v] will store the number of sequences of current length ending with value v
    # Initialize for length 1: each value v in [1, m] forms a valid sequence of length 1
    dp = [0] * (m + 1)
    for v in range(1, m + 1):
        dp[v] = 1

    # Build sequences of length 2 to n
