def lps(s: str) -> int:
    """
    Returns the length of the longest palindromic subsequence in the given string.
    """
    n = len(s)
    if n == 0:
        return 0

    # dp[i][j] will store the length of the longest palindromic subsequence
    # in s[i:j+1]
    dp = [[0] * n for _ in range(n)]

    # Every single character is a palindrome of length 1
    for i in range(n):
        dp[i][i] = 1

    # Fill the table for lengths 2 to n
    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            if s[i] == s[j]:
                if length == 2:
                    dp[i][j] = 2
                else:
                    dp[i][j] = dp[i + 1][j - 1] + 2
            else:
                dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])

    return dp[0][n - 1]
