def count_no_of_ways(n: int, k: int) -> int:
    if n == 0:
        return 0
    if n == 1:
        return k
    if k == 0:
        return 0

    same = k  # ways where current post has same color as previous
    diff = k * (k - 1)  # ways where current post has different color from previous

    for _ in range(2, n + 1):
        new_same = diff  # to have same color now, previous must have been different
        new_diff = (same + diff) * (k - 1)  # to be different now, previous can be same or different
        same, diff = new_same, new_diff

    return same + diff
