import math

def count_binary_seq(n):
    """
    Returns the count of all binary sequences of length 2n such that 
    the sum of the first n bits equals the sum of the last n bits.

    For a given n, each half (first n and last n) can have k ones, where k ranges from 0 to n.
    The number of ways to choose k ones in n bits is C(n, k).
    Total count = sum over k=0 to n of [C(n, k) * C(n, k)]
    """
    def binomial(n, k):
        if k < 0 or k > n:
            return 0
        return math.comb(n, k)

    total = 0
    for k in range(n + 1):
        total += binomial(n, k) * binomial(n, k)

    return float(total)
