def set_left_most_unset_bit(n: int) -> int:
    # Find the leftmost unset bit position (from left, i.e., most significant)
    # We consider bits up to the position of the highest set bit + 1
    if n == 0:
        return 1  # Leftmost unset bit for 0 (binary 0) is at position 0, so set it to 1

    # Find the position of the most significant bit
    msb_position = n.bit_length() - 1

    # Start checking from the most significant bit down to 0
    for i in range(msb_position, -1, -1):
        if not (n & (1 << i)):
            # Found the leftmost unset bit, set it
            return n | (1 << i)

    # If all bits up to msb are set, we need to extend further
    # The next bit position (msb_position + 1) is guaranteed to be unset
    return n | (1 << (msb_position + 1))

# Test case
assert set_left_most_unset_bit(10) == 14
