def bitwise_xor(*tuples):
    if not tuples:
        return ()

    if len(tuples) == 1:
        return tuples[0]

    # Ensure all tuples have the same length
    length = len(tuples[0])
    for t in tuples[1:]:
        if len(t) != length:
            raise ValueError("All tuples must have the same length.")

    result = []
    for i in range(length):
        xor_val = tuples[0][i]
        for t in tuples[1:]:
            xor_val ^= t[i]
        result.append(xor_val)

    return tuple(result)
