def group_tuples(tuples_list):
    from collections import defaultdict

    groups = defaultdict(list)

    for t in tuples_list:
        if not t:
            continue
        first_element = t[0]
        groups[first_element].append(t)

    result = []
    for first_element, group in groups.items():
        if len(group) == 1:
            result.append(group[0])
