    if n <= 0:
        return 0

    total = 0
    i = 1
    while i * i <= n:
        if n % i == 0:
            # Check if i is even
            if i % 2 == 0:
                total += i
            # Check if the pair factor is different and even
            if i * i != n:
                pair = n // i
                if pair % 2 == 0:
                    total += pair
        i += 1
    return total
