def tuple_intersection(tuple_list1, tuple_list2):
    """
    Find the intersection of tuples from two lists, considering tuples as unordered sets.
    Two tuples are considered equal if they contain the same elements regardless of order.
    The result is returned as a set of tuples, where each tuple is sorted to ensure consistent ordering.
    """
    def normalize_tuple(t):
        return tuple(sorted(t))

    set1 = {normalize_tuple(t) for t in tuple_list1}
    set2 = {normalize_tuple(t) for t in tuple_list2}

    intersection = set1 & set2

    # Convert back to tuples with original element order preserved from the input (sorted for consistency)
    result = {tuple(item) for item in intersection}

    return result
